CREATE TABLE `pat_pii_data` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `CODE` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'PII data code',
  `PATIENT_ID` int NOT NULL COMMENT 'Reference to pat_patients',
  `FIRST_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Encrypted first name',
  `MIDDLE_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted middle name',
  `LAST_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Encrypted last name',
  `FULL_NAME` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci GENERATED ALWAYS AS (concat(`FIRST_NAME`,_utf8mb4' ',ifnull(`MIDDLE_NAME`,_utf8mb4''),_utf8mb4' ',`LAST_NAME`)) STORED COMMENT 'Encrypted full name',
  `DATE_OF_BIRTH` date NOT NULL COMMENT 'Date of birth',
