  `SSN` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted Social Security Number',
  `NATIONAL_ID` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted National ID',
  `PASSPORT_NUMBER` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted Passport number',
  `DRIVERS_LICENSE` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted Driver license',
  `EMAIL` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted email address',
  `PHONE_HOME` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted home phone',
  `PHONE_MOBILE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted mobile phone',
  `PHONE_WORK` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted work phone',
  `ADDRESS_LINE1` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted address line 1',
  `ADDRESS_LINE2` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted address line 2',
  `CITY` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted city',
  `STATE` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted state/province',
  `COUNTRY` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'Vietnam' COMMENT 'Country',
  `POSTAL_CODE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted postal code',
  `MAIDEN_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted maiden name',
  `MOTHERS_MAIDEN_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted mother maiden name',
  `FATHERS_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted father name',
  `EMERGENCY_CONTACT_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted emergency contact name',
  `EMERGENCY_CONTACT_RELATIONSHIP` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Emergency contact relationship',
  `EMERGENCY_CONTACT_PHONE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted emergency contact phone',
  `NEXT_OF_KIN_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted next of kin name',
  `NEXT_OF_KIN_RELATIONSHIP` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Next of kin relationship',
  `NEXT_OF_KIN_PHONE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted next of kin phone',
  `GUARDIAN_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted guardian name (for minors)',
  `GUARDIAN_RELATIONSHIP` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Guardian relationship',
  `GUARDIAN_PHONE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Encrypted guardian phone',
  `ENCRYPTION_KEY_ID` int NOT NULL COMMENT 'Encryption key used',
  `ENCRYPTION_VERSION` int DEFAULT '1' COMMENT 'Encryption version',
  `LAST_ACCESSED_AT` datetime DEFAULT NULL COMMENT 'Last access timestamp',
  `ACCESS_COUNT` int DEFAULT '0' COMMENT 'Number of times accessed',
  `DATA_QUALITY_SCORE` decimal(3,2) DEFAULT NULL COMMENT 'Data quality score',
  `VERIFICATION_STATUS` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'UNVERIFIED' COMMENT 'Status: VERIFIED, UNVERIFIED, INVALID',
  `VERIFIED_BY` int DEFAULT NULL COMMENT 'Verified by user ID',
  `VERIFIED_AT` datetime DEFAULT NULL COMMENT 'Verification timestamp',
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `LAST_UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `STATUS` int NOT NULL DEFAULT '1',
  `CREATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_PROGRAM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`ID`),
  UNIQUE KEY `UK_CODE` (`CODE`),
  UNIQUE KEY `UK_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_DATE_OF_BIRTH` (`DATE_OF_BIRTH`),
  KEY `IDX_GENDER` (`GENDER`),
  KEY `IDX_COUNTRY` (`COUNTRY`),
  KEY `IDX_ENCRYPTION_KEY_ID` (`ENCRYPTION_KEY_ID`),
  KEY `IDX_VERIFICATION_STATUS` (`VERIFICATION_STATUS`),
  KEY `IDX_STATUS` (`STATUS`),
  KEY `IDX_CREATED_AT` (`CREATED_AT`),
  KEY `IDX_PAT_PII_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_PAT_PII_DATE_OF_BIRTH` (`DATE_OF_BIRTH`),
  KEY `IDX_PAT_PII_GENDER` (`GENDER`),
  CONSTRAINT `FK_PII_ENCRYPTION_KEY` FOREIGN KEY (`ENCRYPTION_KEY_ID`) REFERENCES `sec_encryption_keys` (`ID`),
  CONSTRAINT `FK_PII_PATIENT` FOREIGN KEY (`PATIENT_ID`) REFERENCES `pat_patients` (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=203 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Encrypted PII Data';
